<?php require __DIR__ . '/config/conexion.php'; $db = conexion(); $res = mysqli_query($db, 'SELECT id, nombre FROM usuarios ORDER BY id DESC LIMIT 1'); $row = mysqli_fetch_assoc($res); if(!$row) die('No users'); $id = $row['id']; echo 'Borrando ID '.$id; $stmt = mysqli_prepare($db, 'DELETE FROM usuarios WHERE id=?'); mysqli_stmt_bind_param($stmt, 'i', $id); if(mysqli_stmt_execute($stmt)) echo ' - EXITOSO'; else echo ' - FALLO: '.mysqli_stmt_error($stmt); ?>
